static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 64;

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    GemmBiasAddHardtanhMishGroupNormCustomTilingData tiling;

    uint32_t batch = static_cast<uint32_t>(context->GetInputShape(0)->GetOriginShape().GetDim(0));
    uint32_t inFeatures = static_cast<uint32_t>(context->GetInputShape(0)->GetOriginShape().GetDim(1));
    uint32_t outFeatures = static_cast<uint32_t>(context->GetInputShape(1)->GetOriginShape().GetDim(0));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    int64_t numGroups = atts->GetAttrPointer<int64_t>(0) ? *attrs->GetAttrPointer<int64_t>(0) : 256;

    // Each block processes one sample (batch index). UB needed per block:
    // out_buf: outFeatures * 4 bytes
    // weight_buf: tileN * tileK * 4 bytes
    // x_buf: tileK * 4 bytes
    // tile_buf: tileN * 4 bytes
    // We'll set tileN=256, tileK=16 based on typical UC.
    uint32_t tileN = 256;
    uint32_t tileK = 16;
    // Check budget: out_buf + weight_buf + x_buf + tile_buf + margin
    uint32_t outBytes = outFeatures * sizeof(float);
    uint32_t weightBytes = tileN * tileK * sizeof(float);
    uint32_t xBytes = tileK * sizeof(float);
    uint32_t tileBytes = tileN * sizeof(float);
    uint32_t total = outBytes + weightBytes + xBytes + tileBytes + 1024;
    if (total > UB_BUDGET_BYTES) {
        // Reduce tile sizes
        if (outBytes > UB_BUDGET_BYTES / 2) {
            // outFeatures too large for one sample – fall back to multi-tile per sample
            tileN = 64;
        }
        // Recompute
        weightBytes = tileN * tileK * sizeof(float);
        total = outBytes + weightBytes + xBytes + tileBytes + 1024;
        if (total > UB_BUDGET_BYTES) {
            // further reduction
            tileN = 32;
            tileK = 8;
        }
    }

    // Ensure alignment
    tileN = (tileN / 64) * 64;
    if (tileN == 0) tileN = 64;
    tileK = (tileK / 16) * 16;
    if (tileK == 0) tileK = 16;

    uint32_t blockDim = batch;  // one block per batch sample
    context->SetBlockDim(blockDim);

    tiling.set_totalBatch(batch);
    tiling.set_outFeatures(outFeatures);
    tiling.set_inFeatures(inFeatures);
    tiling.set_numGroups(static_cast<uint32_t>(numGroups));
    tiling.set_tileN(tileN);
    tiling.set_tileK(tileK);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

